/**
 * Masinis pa_gyvuno_rusis priskyrimas pagal kategorijas — v2
 * petshop.lt — Code Snippets
 * URL: ?assign_gyvuno_rusis2=1          (dry run)
 * URL: ?assign_gyvuno_rusis2=1&confirm=1 (realus priskyrimas)
 */

add_action('init', function() {
    if ( ! isset($_GET['assign_gyvuno_rusis2']) || ! current_user_can('manage_options') ) return;

    $dry_run = ! isset($_GET['confirm']);

    $mapping = [
        // ŠUNIMS
        'sausas-maistas-sunims'         => ['sunims'],
        'zaislai-sunims'                => ['sunims'],
        'skanestai-sunims'              => ['sunims'],
        'konservai-sunims'              => ['sunims'],
        'animonda-konservai-sunims'     => ['sunims'],
        'hipoalerginis-maistas-sunims'  => ['sunims'],
        'higienos-priemones-sunims'     => ['sunims'],
        'zirkles-sunims'                => ['sunims'],
        'sunims'                        => ['sunims'],
        'guoliai-ir-boksai-sunims'      => ['sunims'],
        'antiparazitines-priemones-sunims' => ['sunims'],
        'sampunai-sunims'               => ['sunims'],
        'maistas-sunims'                => ['sunims'],

        // KATĖMS
        'sausas-maistas-katems'         => ['katems'],
        'konservai-katems'              => ['katems'],
        'zaislai-katems'                => ['katems'],
        'kraikai-kacziu-tualetams'      => ['katems'],
        'tualetai'                      => ['katems'],
        'katems'                        => ['katems'],
        'dubeneliai-katems'             => ['katems'],
        'skanestai-katems'              => ['katems'],
        'miamor-katems'                 => ['katems'],
        'vitaminai-ir-papildai-katems'  => ['katems'],
        'maistas-katems'                => ['katems'],
        'priezuros-priemones-katems'    => ['katems'],
        'antiparazitines-priemones-katems' => ['katems'],
        'draskykles-katems'             => ['katems'],

        // ŽUVIMS
        'akvariumo-zuvyciu-maistas'     => ['zuvims'],
        'zuvims'                        => ['zuvims'],
        'tvenkiniu-zuvu-maistas'        => ['zuvims'],

        // GRAUŽIKAMS
        'pasaras-grauzikams'            => ['grauzikams'],
        'grauzikams'                    => ['grauzikams'],
        'skanestai-grauzikams'          => ['grauzikams'],

        // PAUKŠČIAMS
        'lesalas-pauksciums'            => ['pauksciums'],
        'pauksciums'                    => ['pauksciums'],
        'skanestai-pauksciums'          => ['pauksciums'],

        // UNIVERSALŪS (šunims + katėms)
        'antkakliai'                    => ['sunims', 'katems'],
        'antkakliai-pavadeliai-sunims'  => ['sunims', 'katems'],
        'pavadeliai-sunims'             => ['sunims', 'katems'],
        'dubeneliai-sunims'             => ['sunims', 'katems'],
        'kraikai'                       => ['sunims', 'katems'],
        'semtuveliai'                   => ['sunims', 'katems'],
        'tualetai-kraikai-semtuveliai'  => ['katems'],
        'sukos'                         => ['sunims', 'katems'],
        'sepeciai'                      => ['sunims', 'katems'],
        'sukos-sepeciai-zirkles-sunims' => ['sunims', 'katems'],
        'vitaminai-ir-papildai-sunims'  => ['sunims', 'katems'],
        'transportavimo-dezes'          => ['sunims', 'katems'],
        'kelioniu-iranga'               => ['sunims', 'katems'],
    ];

    $assigned   = 0;
    $skipped    = 0;
    $not_mapped = [];

    $all_ids = get_posts([
        'post_type'      => 'product',
        'posts_per_page' => -1,
        'fields'         => 'ids',
    ]);

    foreach ( $all_ids as $product_id ) {
        $cats = get_the_terms($product_id, 'product_cat');
        if ( empty($cats) || is_wp_error($cats) ) continue;

        $cat_slugs = wp_list_pluck($cats, 'slug');
        $rusis_slugs = [];
        $mapped = false;

        foreach ( $cat_slugs as $slug ) {
            if ( isset($mapping[$slug]) ) {
                $rusis_slugs = array_merge($rusis_slugs, $mapping[$slug]);
                $mapped = true;
            }
        }

        if ( ! $mapped ) {
            foreach ($cats as $cat) {
                $not_mapped[$cat->name] = ($not_mapped[$cat->name] ?? 0) + 1;
            }
            $skipped++;
            continue;
        }

        $rusis_slugs = array_unique($rusis_slugs);

        if ( ! $dry_run ) {
            $term_ids = [];
            foreach ($rusis_slugs as $rs) {
                $term = get_term_by('slug', $rs, 'pa_gyvuno_rusis');
                if ( $term ) $term_ids[] = $term->term_id;
            }
            if ( ! empty($term_ids) ) {
                wp_set_object_terms($product_id, $term_ids, 'pa_gyvuno_rusis', false);
                $product = wc_get_product($product_id);
                if ($product) {
                    $attributes = $product->get_attributes();
                    if ( ! isset($attributes['pa_gyvuno_rusis']) ) {
                        $attribute = new WC_Product_Attribute();
                        $attribute->set_id( wc_attribute_taxonomy_id_by_name('pa_gyvuno_rusis') );
                        $attribute->set_name('pa_gyvuno_rusis');
                        $attribute->set_options($term_ids);
                        $attribute->set_position(0);
                        $attribute->set_visible(true);
                        $attribute->set_variation(false);
                        $attributes['pa_gyvuno_rusis'] = $attribute;
                        $product->set_attributes($attributes);
                        $product->save();
                    }
                }
            }
        }

        $assigned++;
    }

    echo '<style>body{font-family:monospace;padding:20px;font-size:14px} table{border-collapse:collapse;width:100%;max-width:700px} td,th{border:1px solid #ccc;padding:6px 10px} tr:nth-child(even){background:#f9f9f9} .ok{color:green} .warn{color:orange}</style>';
    $mode = $dry_run ? '🔍 DRY RUN' : '✅ REALUS PRISKYRIMAS';
    echo "<h2>Gyvūno rūšis — masinis priskyrimas v2</h2>";
    echo "<p><strong>Režimas:</strong> $mode</p>";
    echo "<p class='ok'>✅ Priskirta: <strong>$assigned</strong></p>";
    echo "<p class='warn'>⏭ Praleista: <strong>$skipped</strong></p>";

    if ( ! empty($not_mapped) ) {
        arsort($not_mapped);
        echo "<h3>Likusios be mapping'o:</h3>";
        echo '<table><tr><th>Kategorija</th><th>Prekių sk.</th></tr>';
        foreach ($not_mapped as $cat => $cnt) {
            echo "<tr><td>$cat</td><td>$cnt</td></tr>";
        }
        echo '</table>';
    }

    if ( $dry_run ) {
        echo '<br><p><strong>Jei OK — paleiskite:</strong> <code>?assign_gyvuno_rusis2=1&confirm=1</code></p>';
    } else {
        echo '<br><p class="ok"><strong>Baigta! Patikrinkite frontend filtrą.</strong></p>';
    }
    exit;
});

/**
 * Filtrų sanity check — patikrinti, ar VISOS publish ZB prekės atitinka mūsų taisykles
 * URL: ?zb_sanity=1
 */
add_action('init', function() {
    if ( ! isset($_GET['zb_sanity']) || ! current_user_can('manage_options') ) return;

    global $wpdb;

    echo '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>
        body{font-family:system-ui;max-width:1200px;margin:20px auto;padding:20px;}
        h1,h2{border-bottom:2px solid #2271b1;padding-bottom:5px;}
        table{border-collapse:collapse;width:100%;font-size:13px;margin:10px 0;}
        th,td{padding:8px;border:1px solid #ddd;text-align:left;}
        th{background:#f0f0f0;}
        .ok{color:#2e7d32;font-weight:bold;}
        .err{color:#c62828;font-weight:bold;}
        .warn{color:#f57c00;font-weight:bold;}
        .stats{display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin:15px 0;}
        .stat{background:#f5f5f5;padding:15px;border-radius:4px;border-left:4px solid #2271b1;}
        .stat-val{font-size:28px;font-weight:bold;color:#1976d2;}
        .box{padding:15px;margin:10px 0;border-radius:4px;}
        .box-ok{background:#e8f5e9;border-left:4px solid #2e7d32;}
        .box-warn{background:#fff3cd;border-left:4px solid #f57c00;}
        .box-err{background:#ffcdd2;border-left:4px solid #c62828;}
    </style></head><body>';

    echo '<h1>🔍 ZB Filtrų Sanity Check</h1>';
    echo '<p>' . date('Y-m-d H:i:s') . '</p>';

    // === 1. Pagrindiniai skaičiai ===
    $total_zb = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        WHERE p.post_type='product'
    ");

    $publish_zb = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        WHERE p.post_type='product' AND p.post_status='publish'
    ");

    $draft_zb = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        WHERE p.post_type='product' AND p.post_status='draft'
    ");

    $trash_zb = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        WHERE p.post_type='product' AND p.post_status='trash'
    ");

    echo '<h2>📊 ZB prekių apžvalga</h2>';
    echo '<div class="stats">';
    echo '<div class="stat"><div>Iš viso ZB</div><div class="stat-val">' . number_format($total_zb) . '</div></div>';
    echo '<div class="stat"><div>Publish</div><div class="stat-val" style="color:#2e7d32">' . number_format($publish_zb) . '</div></div>';
    echo '<div class="stat"><div>Draft</div><div class="stat-val" style="color:#f57c00">' . number_format($draft_zb) . '</div></div>';
    echo '</div>';
    echo '<p>Trash: ' . number_format($trash_zb) . '</p>';

    // === 2. Excluded brand check ===
    echo '<h2>1. 🚫 Excluded Brand Check (Hau&Miau, bioVETERINARY, Abakus)</h2>';
    $excluded_publish = $wpdb->get_results("
        SELECT p.ID, p.post_title, pm_brand.meta_value AS brand
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        INNER JOIN {$wpdb->postmeta} pm_brand ON pm_brand.post_id=p.ID AND pm_brand.meta_key='_zb_brand'
        WHERE p.post_type='product' AND p.post_status='publish'
          AND (pm_brand.meta_value LIKE '%Hau%' OR pm_brand.meta_value LIKE '%bioVETERINARY%' OR pm_brand.meta_value LIKE '%Abakus%')
    ");

    if (empty($excluded_publish)) {
        echo '<div class="box box-ok">✅ Excluded brandai NEPUBLISH (visi trash). Filtras veikia.</div>';
    } else {
        echo '<div class="box box-err">❌ Rasta ' . count($excluded_publish) . ' excluded brand publish prekių!</div>';
        echo '<table><tr><th>ID</th><th>Brand</th><th>Pavadinimas</th></tr>';
        foreach ($excluded_publish as $p) {
            echo '<tr><td>' . $p->ID . '</td><td>' . esc_html($p->brand) . '</td><td>' . esc_html($p->post_title) . '</td></tr>';
        }
        echo '</table>';
    }

    // === 3. Cost < €8 check ===
    echo '<h2>2. 💰 Cost < €8 Check</h2>';
    $cheap_publish = $wpdb->get_results("
        SELECT p.ID, p.post_title, pm_cost.meta_value AS cost, pm_brand.meta_value AS brand
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        INNER JOIN {$wpdb->postmeta} pm_cost ON pm_cost.post_id=p.ID AND pm_cost.meta_key='_zb_cost'
        LEFT JOIN {$wpdb->postmeta} pm_brand ON pm_brand.post_id=p.ID AND pm_brand.meta_key='_zb_brand'
        WHERE p.post_type='product' AND p.post_status='publish'
          AND CAST(pm_cost.meta_value AS DECIMAL(10,3)) < 8
        ORDER BY CAST(pm_cost.meta_value AS DECIMAL(10,3)) ASC
        LIMIT 20
    ");

    $cheap_count = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        INNER JOIN {$wpdb->postmeta} pm_cost ON pm_cost.post_id=p.ID AND pm_cost.meta_key='_zb_cost'
        WHERE p.post_type='product' AND p.post_status='publish'
          AND CAST(pm_cost.meta_value AS DECIMAL(10,3)) < 8
    ");

    if ($cheap_count === 0) {
        echo '<div class="box box-ok">✅ Visos publish prekės cost ≥ €8. Filtras veikia.</div>';
    } else {
        echo '<div class="box box-err">❌ Rasta ' . $cheap_count . ' publish prekių su cost < €8!</div>';
        echo '<table><tr><th>ID</th><th>Cost</th><th>Brand</th><th>Pavadinimas</th></tr>';
        foreach ($cheap_publish as $p) {
            echo '<tr><td>' . $p->ID . '</td><td><strong class="err">€' . $p->cost . '</strong></td><td>' . esc_html($p->brand) . '</td><td>' . esc_html($p->post_title) . '</td></tr>';
        }
        echo '</table>';
    }

    // === 4. Qty = 0 check ===
    echo '<h2>3. 📦 Qty = 0 Check</h2>';
    $no_stock = (int)$wpdb->get_var("
        SELECT COUNT(DISTINCT p.ID)
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        INNER JOIN {$wpdb->postmeta} pm_qty ON pm_qty.post_id=p.ID AND pm_qty.meta_key='_zb_qty'
        WHERE p.post_type='product' AND p.post_status='publish'
          AND CAST(pm_qty.meta_value AS DECIMAL(10,3)) = 0
    ");

    if ($no_stock === 0) {
        echo '<div class="box box-ok">✅ Visos publish prekės turi stock > 0. Filtras veikia.</div>';
    } else {
        echo '<div class="box box-warn">⚠️ ' . $no_stock . ' publish prekių su qty=0. (Normalu — prekė buvo publish ir likutis nukrito iki 0.)</div>';
    }

    // === 5. Brandų pasiskirstymas publish prekėse ===
    echo '<h2>4. 🏷️ Brandų pasiskirstymas (publish ZB prekės)</h2>';
    $brands = $wpdb->get_results("
        SELECT pm_brand.meta_value AS brand, COUNT(DISTINCT p.ID) AS cnt
        FROM {$wpdb->posts} p
        INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
        INNER JOIN {$wpdb->postmeta} pm_brand ON pm_brand.post_id=p.ID AND pm_brand.meta_key='_zb_brand'
        WHERE p.post_type='product' AND p.post_status='publish'
        GROUP BY pm_brand.meta_value
        ORDER BY cnt DESC
        LIMIT 30
    ");

    echo '<table><tr><th>Brand</th><th>Publish prekių</th></tr>';
    foreach ($brands as $b) {
        echo '<tr><td>' . esc_html($b->brand) . '</td><td><strong>' . $b->cnt . '</strong></td></tr>';
    }
    echo '</table>';

    // === 6. Kainos intervalai (publish ZB) ===
    echo '<h2>5. 💵 Kainos intervalai (publish ZB)</h2>';
    $price_ranges = [
        ['€8-15', 8, 15],
        ['€15-30', 15, 30],
        ['€30-50', 30, 50],
        ['€50-100', 50, 100],
        ['€100+', 100, 99999],
    ];

    echo '<table><tr><th>Cost intervalas</th><th>Publish prekių</th></tr>';
    foreach ($price_ranges as $r) {
        $cnt = (int)$wpdb->get_var($wpdb->prepare("
            SELECT COUNT(DISTINCT p.ID)
            FROM {$wpdb->posts} p
            INNER JOIN {$wpdb->postmeta} pm ON pm.post_id=p.ID AND pm.meta_key='_zb_enabled' AND pm.meta_value='yes'
            INNER JOIN {$wpdb->postmeta} pm_cost ON pm_cost.post_id=p.ID AND pm_cost.meta_key='_zb_cost'
            WHERE p.post_type='product' AND p.post_status='publish'
              AND CAST(pm_cost.meta_value AS DECIMAL(10,3)) >= %f
              AND CAST(pm_cost.meta_value AS DECIMAL(10,3)) < %f
        ", $r[1], $r[2]));
        echo '<tr><td>' . $r[0] . '</td><td><strong>' . $cnt . '</strong></td></tr>';
    }
    echo '</table>';

    // === 7. Galutinis verdiktas ===
    echo '<h2>🎯 Verdiktas</h2>';
    $errors = (empty($excluded_publish) ? 0 : 1) + ($cheap_count > 0 ? 1 : 0);

    if ($errors === 0) {
        echo '<div class="box box-ok"><strong>✅ VISI FILTRAI VEIKIA TINKAMAI</strong><br>';
        echo 'Excluded brandai → trash<br>';
        echo 'Cost < €8 → trash<br>';
        echo $publish_zb . ' publish prekės ATITINKA visus kriterijus.</div>';
    } else {
        echo '<div class="box box-err"><strong>❌ Rasta filtrų klaidų — žiūrėk aukščiau</strong></div>';
    }

    echo '</body></html>';
    exit;
});

/**
 * VF Pricing S70 Sanity Check v1 (deployed logic test)
 *
 * Vienkartinis diagnostinis snippet'as. Paleidziamas:
 *   https://dev.avesa.lt/?petshop_s70_test=1
 *
 * Reikalavimai:
 *   - prisijunges kaip admin (current_user_can manage_options)
 *   - class-pricing-vf.php v1.5.4 jau ikeltas
 *
 * Veiksmai:
 *   - per Reflection pasiekia private apply_psychological_rounding()
 *   - paleidzia 8 owner'io patvirtintus test cases
 *   - parodo pass/fail kiekvienam
 *   - PAPILDOMAI: integracinis Petshop_Pricing_VF::calculate_final_price_from_xml() testas
 *     (Josera scenarijus su akcija) — patikrina, kad full pricing kelias veikia
 *
 * Jokiu DB pakeitimu. Tik display.
 *
 * Po panaudojimo — disable arba delete sita snippet'a.
 */
add_action( 'init', function() {

	if ( ! isset( $_GET['petshop_s70_test'] ) ) {
		return;
	}

	if ( ! current_user_can( 'manage_options' ) ) {
		wp_die( 'Prieiga draudziama' );
	}

	if ( ! class_exists( 'Petshop_Pricing_VF' ) ) {
		wp_die( 'Klase Petshop_Pricing_VF nerasta — plugin neaktyvus?' );
	}

	header( 'Content-Type: text/plain; charset=utf-8' );
	echo "=== S70 SANITY CHECK — Petshop_Pricing_VF v1.5.4 ===\n\n";

	$pricing = new Petshop_Pricing_VF();

	// ---------- 1. apply_psychological_rounding() test cases ----------
	$ref = new ReflectionClass( $pricing );
	if ( ! $ref->hasMethod( 'apply_psychological_rounding' ) ) {
		echo "✗ FATAL: metodas apply_psychological_rounding() neegzistuoja deployed klaseje.\n";
		echo "   Tikriausiai upload metu failas sugadintas. Re-upload.\n";
		exit;
	}

	$method = $ref->getMethod( 'apply_psychological_rounding' );
	$method->setAccessible( true );

	$round = function( $price ) use ( $method, $pricing ) {
		return $method->invoke( $pricing, $price );
	};

	echo "--- apply_psychological_rounding (8 owner test cases) ---\n";

	$cases = [
		[ 0.85,  0.85,  '< 1 EUR floor' ],
		[ 1.00,  1.00,  '1.09 = +9%, blokuojama' ],
		[ 1.04,  1.09,  'uplift 4.8%, ribose' ],
		[ 4.15,  4.19,  '+0.96%, OK' ],
		[ 4.99,  4.99,  'fix point (jau x9)' ],
		[ 6.43,  6.49,  '+0.93%, OK' ],
		[ 12.46, 12.49, '+0.24%, OK' ],
		[ 42.57, 42.59, '+0.05%, OK' ],
	];

	$pass = 0;
	$fail = 0;
	foreach ( $cases as [ $input, $expected, $note ] ) {
		$got = $round( $input );
		$ok  = ( abs( $got - $expected ) < 0.001 );
		$mark = $ok ? 'PASS' : 'FAIL';
		if ( $ok ) $pass++; else $fail++;
		echo sprintf( "  [%s] %.2f -> %.2f (expected %.2f)  %s\n",
			$mark, $input, $got, $expected, $note );
	}

	echo "\n  Subtotal: {$pass}/" . count( $cases ) . " pass\n\n";

	// ---------- 2. Sale apvalinimas — owner pavyzdys ----------
	echo "--- Sale apvalinimas (regular 16.43 + sale 14.91) ---\n";

	$r = $round( 16.43 );
	$s = $round( 14.91 );
	echo sprintf( "  regular base 16.43 -> %.2f (expected 16.49)\n", $r );
	echo sprintf( "  sale base    14.91 -> %.2f (expected 14.99)\n", $s );
	echo sprintf( "  sale < regular? %s\n\n",
		$s < $r ? 'TAIP — sale galioja' : 'NE — sale isvaloma' );

	// ---------- 3. Fake sale apsauga ----------
	echo "--- Fake sale apsauga (10.05 ir 10.02 abu -> 10.09) ---\n";

	$fr = $round( 10.05 );
	$fs = $round( 10.02 );
	echo sprintf( "  regular base 10.05 -> %.2f\n", $fr );
	echo sprintf( "  sale base    10.02 -> %.2f\n", $fs );
	$fake = $fs >= $fr;
	echo sprintf( "  sale >= regular po apvalinimo? %s\n",
		$fake ? 'TAIP — calculate_final_price_from_xml turi isvalyti sale' : 'NE' );
	echo "\n";

	// ---------- 4. Integracinis: calculate_final_price_from_xml ----------
	echo "--- Integracinis: calculate_final_price_from_xml (Josera) ---\n";

	// Scenarijus A: su akcija. base=10, personal=12, brand Josera (20% discount + 20% markup)
	$result_a = $pricing->calculate_final_price_from_xml( 10.00, 12.00, 'Josera', [] );
	echo "  Scenarijus A: base=10.00 personal=12.00 brand=Josera\n";
	echo "    regular: " . $result_a['regular'] . " (expected 13.99)\n";
	echo "    sale:    " . $result_a['sale']    . " (expected 11.69)\n";
	echo "    rule:    " . $result_a['rule']    . " (expected 'BRAND:Josera +DISC:20%')\n";
	echo "    margin:  " . $result_a['margin_pct'] . "% (expected ~20.76)\n";
	echo "    reasons: " . implode( ', ', $result_a['review_reasons'] ) . "\n";

	$int_ok = (
		abs( $result_a['regular'] - 13.99 ) < 0.01 &&
		abs( $result_a['sale']    - 11.69 ) < 0.01 &&
		$result_a['rule'] === 'BRAND:Josera +DISC:20%'
	);
	echo "    [" . ( $int_ok ? 'PASS' : 'FAIL' ) . "] integracinis Josera A\n\n";

	// Scenarijus B: be akcijos. base = personal
	$result_b = $pricing->calculate_final_price_from_xml( 12.00, 12.00, 'Josera', [] );
	echo "  Scenarijus B: base=12.00 personal=12.00 (be akcijos)\n";
