	$int_b_ok = ( $result_b['sale'] == 0 );
	echo "    [" . ( $int_b_ok ? 'PASS' : 'FAIL' ) . "] integracinis Josera B (be sale)\n\n";

	// ---------- 5. Patikrinimas, kad round_to_99 vis dar yra (backward-compat) ----------
	echo "--- Backward-compat: round_to_99() vis dar egzistuoja ---\n";

	$bc_ok = method_exists( $pricing, 'round_to_99' );
	echo "    [" . ( $bc_ok ? 'PASS' : 'FAIL' ) . "] round_to_99() metodas randamas\n\n";

	// ---------- 6. Total ----------
	$total_pass = $pass + ( $int_ok ? 1 : 0 ) + ( $int_b_ok ? 1 : 0 ) + ( $bc_ok ? 1 : 0 );
	$total_run  = count( $cases ) + 3;

	echo "=== TOTAL: {$total_pass}/{$total_run} pass ===\n";

