 * NIEKO neraso. Tik dengties analizei.
 *
 * Trigger: /?ank_parse=1
 */

add_action('wp_loaded', function () {

    if (empty($_GET['ank_parse'])) { return; }
    if (!is_user_logged_in() || !current_user_can('manage_options')) { return; }

    $cat_ids = array(116);

    /* move-out kandidatai (ne pavadeliai) - is recon */
    $moveout_sku = array(
        'NOB51955','NOB88904','NOB67474','HAPM240', // skanestu deklai (Nobby/Happet)
        '25772',                                     // Nobleza skanestu deklas
        '871913819974',                              // Nobleza vandens fontanas
    );

    $norm = function ($s) {
        $s = function_exists('mb_strtolower') ? mb_strtolower($s, 'UTF-8') : strtolower($s);
        $s = str_replace("\xC2\xA0", ' ', $s);
        $lt = array("\xC4\x85","\xC4\x8D","\xC4\x99","\xC4\x97","\xC4\xAF","\xC5\xA1","\xC5\xB3","\xC5\xAB","\xC5\xBE");
        $en = array('a','c','e','e','i','s','u','u','z');
        return ' ' . preg_replace('/\s+/u', ' ', str_replace($lt, $en, $s)) . ' ';
    };

    /* TIPAS (pirmas pataikymas pagal prioriteta) */
    $tipas_rules = array(
        // apsaugine apykakle (pries antkakli - "apykakle" aiskus signalas)
        'Apsaugine apykakle' => array('apsaugine apykakle','apsaugines apykakle','apykakle'),
