        'Antkaklis'          => array('antkaklis','antkakl'),
    );

    /* MEDZIAGA (multi galimas, bet imam kas matosi) */
    $medz_rules = array(
        'Oda'       => array(' oda ','odos','rieb. odos','riebalintos odos'),
        'Neoprenas' => array('neopren'),
        'Guma'      => array('gumuot',' guma ','gumin'),
        'Virve'     => array('virvin','virve'),
        'Juosta'    => array('juostin','juosta',' tape '),
        'Nailonas'  => array('nailon','nylon'),
        'Plastikas' => array('plastik','tpu'),
        'Metalas'   => array('metal','grandin'),
    );

    /* DYDIS (intervalai isskaidomi) */
    $size_tokens = array('xs','s','m','l','xl','xxl','2xl','3xl');

    $parse_size = function ($hay) {
        // randa tokenus su ribomis: "xs-s", "m-l", "l-xl", " m ", "2xl/3"
        $found = array();
        // intervalai
        $pairs = array(
            'xs-s' => array('XS','S'), 's-m' => array('S','M'), 'm-l' => array('M','L'),
            'l-xl' => array('L','XL'), 'xl-xxl' => array('XL','XXL'), 'm-xl' => array('M','XL'),
        );
        foreach ($pairs as $tok => $vals) {
            if (strpos($hay, ' ' . $tok . ' ') !== false || strpos($hay, $tok . ' ') !== false
                || strpos($hay, ' ' . $tok) !== false) {
                foreach ($vals as $v) { $found[$v] = true; }
            }
        }
        // pavieniai (su ribomis, kad "s" nepagautu vidury zodzio)
        $singles = array(
            '2xl' => 'XXL', '3xl' => 'XXL', 'xxl' => 'XXL', 'xl' => 'XL',
            'xs' => 'XS', ' l ' => 'L', ' m ' => 'M', ' s ' => 'S',
        );
        foreach ($singles as $tok => $v) {
            $t = (strlen(trim($tok)) <= 1) ? $tok : (' ' . trim($tok));
            if (strpos($hay, $tok) !== false) { $found[$v] = true; }
        }
        // isvalom: jei yra XX/XL grupiu, "L"/"M" pavieniai jau gali buti is intervalu - OK
        return array_keys($found);
    };

    /* PAVADELIO ILGIS (metrais + automatinis) */
    $parse_len = function ($hay) {
        $out = array();
        if (strpos($hay, 'flexi') !== false || strpos($hay, 'automatin') !== false
            || strpos($hay, 'one touch') !== false) { $out['Automatinis'] = true; }
        // "5m", "5 m", "1,33-1,80 m", "10 m" -> imam visus skaicius pries m
        if (preg_match_all('/(\d+(?:[.,]\d+)?)\s*m\b/u', $hay, $mm)) {
            foreach ($mm[1] as $num) {
                $n = (float) str_replace(',', '.', $num);
                if ($n >= 1 && $n <= 20) { $out[rtrim(rtrim((string) $n, '0'), '.') . 'm'] = true; }
            }
        }
        return array_keys($out);
    };

    $q = new WP_Query(array(
        'post_type' => 'product', 'post_status' => array('publish', 'draft'),
        'posts_per_page' => -1, 'fields' => 'ids', 'no_found_rows' => true,
        'tax_query' => array(array('taxonomy' => 'product_cat', 'field' => 'term_id', 'terms' => $cat_ids)),
    ));

    $rows = array();
    $cov = array('tipas' => 0, 'dydis' => 0, 'medz' => 0, 'ilgis' => 0);
    $no_tipas = array(); $moveout = array();

    foreach ($q->posts as $pid) {
        $sku  = (string) get_post_meta($pid, '_sku', true);
        $name = get_the_title($pid);
        if (in_array($sku, $moveout_sku, true)) { $moveout[] = array($pid, $sku, $name); continue; }

        $hay = $norm($name);

        $tipas = '';
        foreach ($tipas_rules as $t => $kws) {
            foreach ($kws as $kw) { if (strpos($hay, $kw) !== false) { $tipas = $t; break 2; } }
        }
        $medz = array();
        foreach ($medz_rules as $m => $kws) {
            foreach ($kws as $kw) { if (strpos($hay, $kw) !== false) { $medz[] = $m; break; } }
        }
        $dydis = $parse_size($hay);
        $ilgis = $parse_len($hay);

        if ($tipas) { $cov['tipas']++; } else { $no_tipas[] = array($pid, $sku, $name); }
        if ($dydis) { $cov['dydis']++; }
        if ($medz)  { $cov['medz']++; }
        if ($ilgis) { $cov['ilgis']++; }

        $rows[] = array($pid, $sku, $name, $tipas, $dydis, $medz, $ilgis);
    }

    $tot = count($rows);
    echo '<!doctype html><meta charset="utf-8"><style>'
       . 'body{font:12px system-ui,Arial;margin:24px;} table{border-collapse:collapse;margin:6px 0 16px;} '
       . 'td,th{border:1px solid #ccc;padding:3px 7px;vertical-align:top;} th{background:#f3f3f3;} '
       . '.m{color:#999;} .t{color:#1a6;} .d{color:#06c;} .z{color:#a60;} .r{background:#fff6f0;}</style>';

    echo '<h2>Antkakliai/pavadeliai PARSE-TEST</h2>';
    echo '<p>Viso (be move-out): <b>' . $tot . '</b> &middot; tipas: <b>' . $cov['tipas'] . '</b> (' . ($tot ? round($cov['tipas'] * 100 / $tot) : 0) . '%) &middot; '
       . 'dydis: <b>' . $cov['dydis'] . '</b> &middot; medziaga: <b>' . $cov['medz'] . '</b> &middot; ilgis: <b>' . $cov['ilgis'] . '</b> &middot; '
       . 'MOVE-OUT: <b>' . count($moveout) . '</b> &middot; be tipo (REVIEW): <b>' . count($no_tipas) . '</b></p>';

    echo '<h3>Visos prekes</h3>';
    echo '<table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th><th>tipas</th><th>dydis</th><th>medziaga</th><th>ilgis</th></tr>';
    foreach ($rows as $r) {
        echo '<tr><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td>'
           . '<td class="t">' . esc_html($r[3] ?: '—') . '</td>'
           . '<td class="d">' . esc_html(implode('/', $r[4]) ?: '—') . '</td>'
           . '<td class="z">' . esc_html(implode('/', $r[5]) ?: '—') . '</td>'
           . '<td>' . esc_html(implode('/', $r[6]) ?: '—') . '</td></tr>';
    }
    echo '</table>';

    if ($no_tipas) {
        echo '<h3 class="r">Be tipo (REVIEW)</h3><table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th></tr>';
        foreach ($no_tipas as $r) { echo '<tr class="r"><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td></tr>'; }
        echo '</table>';
    }
    if ($moveout) {
        echo '<h3>MOVE-OUT kandidatai</h3><table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th></tr>';
        foreach ($moveout as $r) { echo '<tr><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td></tr>'; }
        echo '</table>';
    }

    echo '<p class="m">read-only. Niekas nepakeista.</p>';
    exit;
});

/**
 * Antkakliai/pavadeliai (116) - PARSE-TEST v2 (pataisyta diagnoze)
 *
 * READ-ONLY. Pataisytas parseris (v1 klaidos istaisytos):
 *  - Oda: zodzio riba (' oda',' odos') -> "juodos" nebepagauna
 *  - Ilgis: 10m formatas (ne "1m"); mm nepagauna; flexi -> Automatinis
 *  - Automatinis: TIK flexi (be 'one touch')
 *  - Zibintuvelis -> REVIEW (ne Pavadelis)
 *  - Dydis: intervalai + K9 "M/0" + "raide+skaicius" + FLEXI "raide+virvinis"
 *    -> "3 m ilgio" nebeduoda M; 2XL/3 nebedvigubina
 *  - Move-out: Nobleza deklas (SKU 871913821950) itrauktas
 *
 * Rodo dengti, distinct verciu santraukas, pilna lentele, REVIEW, MOVE-OUT.
 * Trigger: /?ank_parse2=1
 */

add_action('wp_loaded', function () {

    if (empty($_GET['ank_parse2'])) { return; }
    if (!is_user_logged_in() || !current_user_can('manage_options')) { return; }

    $cat_ids = array(116);

    /* MOVE-OUT (ne pavadeliai) pagal SKU */
    $moveout_sku = array(
        'NOB51955', 'NOB88904', 'NOB67474', 'HAPM240', // skanestu deklai (Nobby/Happet)
        '871913821950',                                 // Nobleza skanestu deklas (id 25772)
        '871913819974',                                 // Nobleza vandens fontanas (id 27071)
    );

    $norm = function ($s) {
        $s = function_exists('mb_strtolower') ? mb_strtolower($s, 'UTF-8') : strtolower($s);
        $s = str_replace("\xC2\xA0", ' ', $s);
        $lt = array("\xC4\x85","\xC4\x8D","\xC4\x99","\xC4\x97","\xC4\xAF","\xC5\xA1","\xC5\xB3","\xC5\xAB","\xC5\xBE");
        $en = array('a','c','e','e','i','s','u','u','z');
        $s = str_replace($lt, $en, $s);
        // ndash/mdash -> minusas
        $s = str_replace(array("\xE2\x80\x93","\xE2\x80\x94"), '-', $s);
        return ' ' . preg_replace('/\s+/u', ' ', $s) . ' ';
    };

    /* TIPAS */
    $tipas_rules = array(
        'Apsaugine apykakle' => array('apykakl'),
        'Antsnukis'          => array('antsnuk'),
        'Petnesos'           => array('petnes', 'powerharness', 'harness'),
        'Juosmens dirzas'    => array('juosmens dirz', 'begimo pavadel', 'begimo pavady'),
        'Pavadelis'          => array('pavadel', 'pavady', 'pavadys'),
        'Antkaklis'          => array('antkakl'),
    );

    $detect_tipas = function ($hay) use ($tipas_rules) {
        if (strpos($hay, 'zibintuv') !== false) { return ''; } // sviestuvas -> REVIEW
        foreach ($tipas_rules as $t => $kws) {
            foreach ($kws as $kw) { if (strpos($hay, $kw) !== false) { return $t; } }
        }
        return '';
    };

    /* MEDZIAGA */
    $medz_rules = array(
        'Oda'       => array(' oda', ' odos', 'odine', 'odinis'),
        'Neoprenas' => array('neopren'),
        'Guma'      => array('gumuot', ' guma', 'gumin'),
        'Virve'     => array('virvin', 'virve'),
        'Juosta'    => array('juostin', 'juosta', ' tape'),
        'Nailonas'  => array('nailon', 'nylon'),
        'Plastikas' => array('plastik', 'tpu'),
        'Metalas'   => array('metalas', 'metalin'),
    );
    $detect_medz = function ($hay) use ($medz_rules) {
        $out = array();
        foreach ($medz_rules as $m => $kws) {
            foreach ($kws as $kw) { if (strpos($hay, $kw) !== false) { $out[] = $m; break; } }
        }
        return $out;
    };

    /* DYDIS */
    $order = array('XS' => 0, 'S' => 1, 'M' => 2, 'L' => 3, 'XL' => 4, 'XXL' => 5);
    $map3 = function ($t) { $u = strtoupper($t); return ($u === '2XL' || $u === '3XL') ? 'XXL' : $u; };
    $detect_size = function ($hay) use ($order, $map3) {
        $f = array();
        $pairs = array(
            'xs-s' => array('XS', 'S'), 's-m' => array('S', 'M'), 'm-l' => array('M', 'L'),
            'l-xl' => array('L', 'XL'), 'xl-xxl' => array('XL', 'XXL'), 'm-xl' => array('M', 'XL'), 's-l' => array('S', 'L'),
        );
        foreach ($pairs as $tok => $vals) {
            if (preg_match('#(?<![a-z0-9])' . $tok . '(?![a-z0-9])#', $hay)) {
                foreach ($vals as $v) { $f[$v] = true; }
            }
        }
        // K9: raide/skaicius (M/0, XL/2, 2XL/3)
        if (preg_match_all('#(?<![a-z0-9])(2xl|3xl|xxl|xl|xs|s|m|l)/\d#', $hay, $mm)) {
            foreach ($mm[1] as $t) { $f[$map3($t)] = true; }
        }
        // raide [:] tarpas skaicius (M 38-45cm, S: 30-34)
        if (preg_match_all('#(?<![a-z0-9])(2xl|3xl|xxl|xl|xs|s|m|l):?\s+\d#', $hay, $mm)) {
            foreach ($mm[1] as $t) { $f[$map3($t)] = true; }
        }
        // FLEXI: raide + virvinis/juostinis/tape
        if (preg_match_all('#(?<![a-z0-9])(xs|xl|s|m|l)\s+(?:virvin|juostin|tape)#', $hay, $mm)) {
            foreach ($mm[1] as $t) { $f[strtoupper($t)] = true; }
        }
        $keys = array_keys($f);
        usort($keys, function ($a, $b) use ($order) { return $order[$a] - $order[$b]; });
        return $keys;
    };

    /* PAVADELIO ILGIS (metrai + automatinis) */
    $detect_len = function ($hay) {
        $out = array();
        if (strpos($hay, 'flexi') !== false) { $out['Automatinis'] = true; }
        if (preg_match_all('#(\d+(?:[.,]\d+)?)\s*m(?![a-z0-9])#', $hay, $mm)) {
            foreach ($mm[1] as $num) {
                $n = (float) str_replace(',', '.', $num);
                if ($n >= 0.5 && $n <= 20) {
                    $s = (floor($n) == $n) ? (string) (int) $n : rtrim(rtrim(number_format($n, 2, '.', ''), '0'), '.');
                    $out[$s . 'm'] = true;
                }
            }
        }
        $keys = array_keys($out);
        sort($keys); // Automatinis -> i pabaiga del didziosios A < skaiciai? -> rikiuojam custom
        usort($keys, function ($a, $b) {
            if ($a === 'Automatinis') { return 1; }
            if ($b === 'Automatinis') { return -1; }
            return (float) $a - (float) $b;
        });
        return $keys;
    };

    $q = new WP_Query(array(
        'post_type' => 'product', 'post_status' => array('publish', 'draft'),
        'posts_per_page' => -1, 'fields' => 'ids', 'no_found_rows' => true,
        'tax_query' => array(array('taxonomy' => 'product_cat', 'field' => 'term_id', 'terms' => $cat_ids)),
    ));

    $rows = array(); $moveout = array(); $no_tipas = array();
    $cov = array('tipas' => 0, 'dydis' => 0, 'medz' => 0, 'ilgis' => 0);
    $sum = array('tipas' => array(), 'dydis' => array(), 'medz' => array(), 'ilgis' => array());

    foreach ($q->posts as $pid) {
        $sku  = (string) get_post_meta($pid, '_sku', true);
        $name = get_the_title($pid);
        if (in_array($sku, $moveout_sku, true)) { $moveout[] = array($pid, $sku, $name); continue; }

        $hay   = $norm($name);
        $tipas = $detect_tipas($hay);
        $medz  = $tipas ? $detect_medz($hay) : array();
        $dydis = $tipas ? $detect_size($hay) : array();
        $ilgis = $tipas ? $detect_len($hay)  : array();

        if ($tipas) { $cov['tipas']++; $sum['tipas'][$tipas] = ($sum['tipas'][$tipas] ?? 0) + 1; }
        else { $no_tipas[] = array($pid, $sku, $name); }
        if ($dydis) { $cov['dydis']++; foreach ($dydis as $d) { $sum['dydis'][$d] = ($sum['dydis'][$d] ?? 0) + 1; } }
        if ($medz)  { $cov['medz']++;  foreach ($medz as $m) { $sum['medz'][$m] = ($sum['medz'][$m] ?? 0) + 1; } }
        if ($ilgis) { $cov['ilgis']++; foreach ($ilgis as $l) { $sum['ilgis'][$l] = ($sum['ilgis'][$l] ?? 0) + 1; } }

        $rows[] = array($pid, $sku, $name, $tipas, $dydis, $medz, $ilgis);
    }

    $tot = count($rows);
    echo '<!doctype html><meta charset="utf-8"><style>'
       . 'body{font:12px system-ui,Arial;margin:24px;} table{border-collapse:collapse;margin:6px 0 16px;} '
       . 'td,th{border:1px solid #ccc;padding:3px 7px;vertical-align:top;} th{background:#f3f3f3;} '
       . '.m{color:#999;} .t{color:#1a6;} .d{color:#06c;} .z{color:#a60;} .r{background:#fff6f0;} '
       . 'h3{margin:18px 0 4px;} .sum td{padding:2px 10px;}</style>';

    echo '<h2>Antkakliai/pavadeliai PARSE-TEST v2 (pataisyta)</h2>';
    echo '<p>Viso (be move-out): <b>' . $tot . '</b> &middot; tipas: <b>' . $cov['tipas'] . '</b> (' . ($tot ? round($cov['tipas'] * 100 / $tot) : 0) . '%) &middot; '
       . 'dydis: <b>' . $cov['dydis'] . '</b> &middot; medziaga: <b>' . $cov['medz'] . '</b> &middot; ilgis: <b>' . $cov['ilgis'] . '</b> &middot; '
       . 'MOVE-OUT: <b>' . count($moveout) . '</b> &middot; be tipo (REVIEW): <b>' . count($no_tipas) . '</b></p>';

    /* distinct santraukos */
    $print_sum = function ($title, $arr) use ($order) {
        echo '<h3>' . $title . '</h3><table class="sum"><tr><th>Verte</th><th>Kiek</th></tr>';
        if ($title === 'DYDIS') { uksort($arr, function ($a, $b) use ($order) { return ($order[$a] ?? 9) - ($order[$b] ?? 9); }); }
        else { arsort($arr); }
        foreach ($arr as $k => $v) { echo '<tr><td>' . esc_html($k) . '</td><td>' . $v . '</td></tr>'; }
        echo '</table>';
    };
    echo '<div style="display:flex;gap:24px;flex-wrap:wrap;">';
    echo '<div>'; $print_sum('TIPAS', $sum['tipas']); echo '</div>';
    echo '<div>'; $print_sum('DYDIS', $sum['dydis']); echo '</div>';
    echo '<div>'; $print_sum('MEDZIAGA', $sum['medz']); echo '</div>';
    echo '<div>'; $print_sum('ILGIS', $sum['ilgis']); echo '</div>';
    echo '</div>';

    echo '<h3>Visos prekes</h3>';
    echo '<table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th><th>tipas</th><th>dydis</th><th>medziaga</th><th>ilgis</th></tr>';
    foreach ($rows as $r) {
        echo '<tr><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td>'
           . '<td class="t">' . esc_html($r[3] ?: '-') . '</td>'
           . '<td class="d">' . esc_html(implode('/', $r[4]) ?: '-') . '</td>'
           . '<td class="z">' . esc_html(implode('/', $r[5]) ?: '-') . '</td>'
           . '<td>' . esc_html(implode('/', $r[6]) ?: '-') . '</td></tr>';
    }
    echo '</table>';

    if ($no_tipas) {
