});

/**
 * Dubeneliai (111) - PARSE-TEST (diagnoze)
 *
 * READ-ONLY. Atpazinimas is pavadinimo: pa_tipas + pa_medziaga.
 * Guard'ai:
 *  - "su minkstu kilimeliu" = dubuo SU kilimeliu, NE kilimelis (padeklas)
 *  - dozator + semti = semtuvas -> REVIEW (ne dubuo)
 *  - dangtel / biriu(tara) = move-out (maisto laikymas)
 * NIEKO neraso.
 *
 * Trigger: /?dub_parse=1
 */

add_action('wp_loaded', function () {

    if (empty($_GET['dub_parse'])) { return; }
    if (!is_user_logged_in() || !current_user_can('manage_options')) { return; }

    $cat_ids = array(111);

    $norm = function ($s) {
        $s = function_exists('mb_strtolower') ? mb_strtolower($s, 'UTF-8') : strtolower($s);
        $s = str_replace("\xC2\xA0", ' ', $s);
        $lt = array("\xC4\x85","\xC4\x8D","\xC4\x99","\xC4\x97","\xC4\xAF","\xC5\xA1","\xC5\xB3","\xC5\xAB","\xC5\xBE");
        $en = array('a','c','e','e','i','s','u','u','z');
        $s = str_replace($lt, $en, $s);
        $s = str_replace(array("\xE2\x80\x93","\xE2\x80\x94"), '-', $s);
        return ' ' . preg_replace('/\s+/u', ' ', $s) . ' ';
    };

    /* TIPAS detekcija (su guard'ais) */
    $detect_tipas = function ($hay) {
        // move-out -> grazina '#MOVE'
        if (strpos($hay, 'dangtel') !== false) { return '#MOVE'; }
        if (strpos($hay, 'biriu') !== false || strpos($hay, ' tara ') !== false) { return '#MOVE'; }
        // semtuvas -> REVIEW (scoop, ne dubuo)
        if (strpos($hay, 'semti') !== false || strpos($hay, 'semtuv') !== false) { return ''; }

        if (strpos($hay, 'serykl') !== false || strpos($hay, 'girdykl') !== false
            || strpos($hay, 'fontan') !== false || strpos($hay, 'gertuv') !== false
            || strpos($hay, 'dispenser') !== false || strpos($hay, 'eat and drink') !== false
            || strpos($hay, 'maya') !== false) {
            return 'Automatine serykla/girdykla';
        }
        if (strpos($hay, 'leto valgymo') !== false || strpos($hay, 'slow') !== false) {
            return 'Leto valgymo';
        }
        if (strpos($hay, 'ant stovo') !== false || strpos($hay, 'ant medinio stovo') !== false
            || strpos($hay, 'stovas su') !== false || strpos($hay, 'medzio stovas') !== false) {
            return 'Dubuo ant stovo';
        }
        if (strpos($hay, 'sulankstom') !== false || strpos($hay, 'squeeze') !== false
            || strpos($hay, 'kelionin') !== false) {
            return 'Sulankstomas';
        }
        // Padeklas/kilimelis - TIK standalone (ne "su minkstu kilimeliu")
        $is_mat = false;
        if (strpos($hay, 'padekl') !== false) { $is_mat = true; }
        elseif (strpos($hay, 'kilimel') !== false
                && strpos($hay, 'su minkstu') === false
                && strpos($hay, 'su kilimel') === false) { $is_mat = true; }
        if ($is_mat) { return 'Padeklas/kilimelis'; }

        if (strpos($hay, 'dvigubas') !== false || strpos($hay, 'double') !== false) {
            return 'Dvigubas dubuo';
        }
        if (strpos($hay, 'dubenel') !== false || strpos($hay, 'dubuo') !== false
            || strpos($hay, 'indas') !== false) {
            return 'Dubuo';
        }
        return '';
    };

    /* MEDZIAGA (multi) */
    $medz_rules = array(
        'Keramika' => array('keramik', 'keramin'),
        'Bambukas' => array('bambuk'),
        'Metalas'  => array('nerud', 'plien', 'metal', 'inox'),
        'Plastikas'=> array('plastik', ' pp'),
        'Silikonas'=> array('silikon'),
        'Medis'    => array('medin', 'medzio', 'medis', 'pusis'),
    );
    $detect_medz = function ($hay) use ($medz_rules) {
        $out = array();
        foreach ($medz_rules as $m => $kws) {
            foreach ($kws as $kw) { if (strpos($hay, $kw) !== false) { $out[] = $m; break; } }
        }
        return $out;
    };

    $q = new WP_Query(array(
        'post_type' => 'product', 'post_status' => array('publish', 'draft'),
        'posts_per_page' => -1, 'fields' => 'ids', 'no_found_rows' => true,
        'tax_query' => array(array('taxonomy' => 'product_cat', 'field' => 'term_id', 'terms' => $cat_ids)),
    ));

    $rows = array(); $moveout = array(); $no_tipas = array();
    $cov = array('tipas' => 0, 'medz' => 0);
    $sum = array('tipas' => array(), 'medz' => array());

    foreach ($q->posts as $pid) {
        $sku  = (string) get_post_meta($pid, '_sku', true);
        $name = get_the_title($pid);
        $hay  = $norm($name);
        $tipas = $detect_tipas($hay);

        if ($tipas === '#MOVE') { $moveout[] = array($pid, $sku, $name); continue; }

        $medz = $detect_medz($hay);
        if ($tipas) { $cov['tipas']++; $sum['tipas'][$tipas] = ($sum['tipas'][$tipas] ?? 0) + 1; }
        else { $no_tipas[] = array($pid, $sku, $name); }
        if ($medz) { $cov['medz']++; foreach ($medz as $m) { $sum['medz'][$m] = ($sum['medz'][$m] ?? 0) + 1; } }

        $rows[] = array($pid, $sku, $name, $tipas, $medz);
    }

    $tot = count($rows);
    echo '<!doctype html><meta charset="utf-8"><style>'
       . 'body{font:12px system-ui,Arial;margin:24px;} table{border-collapse:collapse;margin:6px 0 14px;} '
       . 'td,th{border:1px solid #ccc;padding:3px 7px;vertical-align:top;} th{background:#f3f3f3;} '
       . '.m{color:#999;} .t{color:#1a6;} .z{color:#a60;} .r{background:#fff6f0;} h3{margin:16px 0 4px;} .sum td{padding:2px 10px;}</style>';

    echo '<h2>Dubeneliai PARSE-TEST</h2>';
    echo '<p>Viso (be move-out): <b>' . $tot . '</b> &middot; tipas: <b>' . $cov['tipas'] . '</b> (' . ($tot ? round($cov['tipas'] * 100 / $tot) : 0) . '%) &middot; '
       . 'medziaga: <b>' . $cov['medz'] . '</b> &middot; MOVE-OUT: <b>' . count($moveout) . '</b> &middot; be tipo (REVIEW): <b>' . count($no_tipas) . '</b></p>';

    echo '<div style="display:flex;gap:24px;flex-wrap:wrap;">';
    echo '<div><h3>TIPAS</h3><table class="sum"><tr><th>Verte</th><th>Kiek</th></tr>';
    arsort($sum['tipas']);
    foreach ($sum['tipas'] as $k => $v) { echo '<tr><td>' . esc_html($k) . '</td><td>' . $v . '</td></tr>'; }
    echo '</table></div>';
    echo '<div><h3>MEDZIAGA</h3><table class="sum"><tr><th>Verte</th><th>Kiek</th></tr>';
    arsort($sum['medz']);
    foreach ($sum['medz'] as $k => $v) { echo '<tr><td>' . esc_html($k) . '</td><td>' . $v . '</td></tr>'; }
    echo '</table></div></div>';

    echo '<h3>Visos prekes</h3>';
    echo '<table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th><th>tipas</th><th>medziaga</th></tr>';
    foreach ($rows as $r) {
        echo '<tr><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td>'
           . '<td class="t">' . esc_html($r[3] ?: '-') . '</td>'
           . '<td class="z">' . esc_html(implode('/', $r[4]) ?: '-') . '</td></tr>';
    }
    echo '</table>';

    if ($no_tipas) {
        echo '<h3 class="r">Be tipo (REVIEW)</h3><table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th></tr>';
        foreach ($no_tipas as $r) { echo '<tr class="r"><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td></tr>'; }
        echo '</table>';
    }
    if ($moveout) {
        echo '<h3>MOVE-OUT kandidatai</h3><table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th></tr>';
        foreach ($moveout as $r) { echo '<tr><td>' . $r[0] . '</td><td class="m">' . esc_html($r[1]) . '</td><td>' . esc_html($r[2]) . '</td></tr>'; }
        echo '</table>';
    }

    echo '<p class="m">read-only. Niekas nepakeista.</p>';
    exit;
});

/**
 * Guoliu/transporto/narvu blokas - pa_tipas + pa_dydis PARSE-TEST (read-only)
 *
 * Kategorijos: 233, Guoliai katems, 122, 121, 123, 125.
 * pa_tipas (16) + pa_dydis (XS..XXL is pavadinimo). JOKIU RASYMU.
 * Trigger: /?guol_attr=1
 */

add_action('wp_loaded', function () {

    if (empty($_GET['guol_attr'])) { return; }
    if (!is_user_logged_in() || !current_user_can('manage_options')) { return; }

    $GK = get_term_by('slug', 'guoliai-katems', 'product_cat');
    $GK_ID = $GK ? (int) $GK->term_id : 0;
    $CATS = array(233, 122, 121, 123, 125);
    if ($GK_ID) { $CATS[] = $GK_ID; }

    $norm = function ($s) {
        $s = function_exists('mb_strtolower') ? mb_strtolower($s, 'UTF-8') : strtolower($s);
        $s = str_replace("\xC2\xA0", ' ', $s);
        $lt = array("\xC4\x85","\xC4\x8D","\xC4\x99","\xC4\x97","\xC4\xAF","\xC5\xA1","\xC5\xB3","\xC5\xAB","\xC5\xBE");
        $en = array('a','c','e','e','i','s','u','u','z');
        $s = str_replace($lt, $en, $s);
        return ' ' . preg_replace('/\s+/u', ' ', $s) . ' ';
    };

    $tipas = function ($n) {
        $h = function ($x) use ($n) { return strpos($n, $x) !== false; };
        $a = function ($arr) use ($n) { foreach ($arr as $k) { if (strpos($n, $k) !== false) { return true; } } return false; };
        if ($h('ratukai')) { return 'Bokso aksesuaras'; }
        if ($h('narvas')) { return 'Narvas'; }
        if ($h('pertvara')) { return 'Automobilio pertvara'; }
        if ($h('uztiesal')) { return 'Automobilio uztiesalas'; }
        if ($h('laiptel') || $h('laiptai')) { return 'Laipteliai'; }
        if ($h('automobil') && $h('guolis')) { return 'Automobilinis guolis'; }
        if ($h('vezimelis')) { return 'Vezimelis'; }
        if ($h('kuprine')) { return 'Kuprine'; }
        if ($a(array('krepsys','tase','rankine','pernesimo'))) { return 'Transportavimo krepsys'; }
        if ($a(array('boksas','transportavimo deze','cosmos','pratiko','rocket','transportino','spark','capri','skudo','rata','transporteris'))) { return 'Transportavimo boksas'; }
        if ($h('urvas')) { return 'Guolis-urvas'; }
        if ($a(array('namas','tunelis','slept','palapine'))) { return 'Namas/sleptuve'; }
        if ($a(array('antklod','pledas'))) { return 'Antklode/pledas'; }
        if ($a(array('kilimel'))) { return 'Kilimelis'; }
        if ($a(array('guolis','gultas','lova','indas'))) { return 'Guolis'; }
        return '(REVIEW)';
    };

    $dydis = function ($name) {
        preg_match_all('/(?<![A-Za-z0-9])(XXL|XL|XS|S|M|L)(?![A-Za-z0-9])/', $name, $m);
        $out = array();
        foreach ($m[1] as $sz) { if (!in_array($sz, $out, true)) { $out[] = $sz; } }
        return $out;
    };

    $q = new WP_Query(array(
        'post_type' => 'product', 'post_status' => array('publish', 'draft'),
        'posts_per_page' => -1, 'fields' => 'ids', 'no_found_rows' => true,
        'tax_query' => array(array('taxonomy' => 'product_cat', 'field' => 'term_id', 'terms' => $CATS)),
    ));

    $rows = array(); $tt = array(); $dd = 0; $rev = 0;
    foreach ($q->posts as $pid) {
        $name = get_the_title($pid);
        $t = $tipas($norm($name));
        $sz = $dydis($name);
        if ($t === '(REVIEW)') { $rev++; }
        if (!isset($tt[$t])) { $tt[$t] = 0; } $tt[$t]++;
        if ($sz) { $dd++; }
        $rows[] = array($pid, get_post_meta($pid, '_sku', true), $name, $t, implode('/', $sz));
    }

    usort($rows, function ($a, $b) { return strcmp($a[3], $b[3]); });

    echo '<!doctype html><meta charset="utf-8"><style>body{font:11px system-ui,Arial;margin:18px;} '
       . 'table{border-collapse:collapse;} td,th{border:1px solid #ccc;padding:2px 6px;} th{background:#f3f3f3;} '
       . '.m{color:#999;} .t{color:#06c;font-weight:bold;} .rev{background:#fde8e8;}</style>';

    echo '<h2>Guoliu/transporto blokas: pa_tipas + pa_dydis (PARSE-TEST)</h2>';
    echo '<p>Viso: <b>' . count($rows) . '</b> &middot; su dydziu: <b>' . $dd . '</b> &middot; REVIEW: <b>' . $rev . '</b></p>';

    echo '<h3>pa_tipas pasiskirstymas</h3><table><tr><th>Tipas</th><th>Kiek</th></tr>';
    arsort($tt);
    foreach ($tt as $k => $v) { echo '<tr><td>' . esc_html($k) . '</td><td>' . $v . '</td></tr>'; }
    echo '</table>';

    echo '<h3>Visos prekes</h3><table><tr><th>ID</th><th>SKU</th><th>Pavadinimas</th><th>tipas</th><th>dydis</th></tr>';
    foreach ($rows as $r) {
        list($pid, $sku, $name, $t, $sz) = $r;
        echo '<tr' . ($t === '(REVIEW)' ? ' class="rev"' : '') . '><td>' . $pid . '</td><td class="m">' . esc_html($sku) . '</td>'
           . '<td>' . esc_html($name) . '</td><td class="t">' . esc_html($t) . '</td><td>' . esc_html($sz ?: '-') . '</td></tr>';
    }
    echo '</table>';
    echo '<p class="m">read-only. Niekas nepakeista.</p>';
    exit;
});

