add_action('init', function(){
  if ( ! isset($_GET['ps_samp_inspect2']) ) return;
  if ( ($_GET['k'] ?? '') !== 'ps2026' ) { status_header(403); echo 'no'; exit; }
  header('Content-Type: application/json; charset=utf-8');
  $get = function($slug){
