    if(!$p) return null;
    $f = get_post_meta($p->ID,'_filters',true);
    if(is_string($f)) $f = maybe_unserialize($f);
    return is_array($f)&&isset($f[1]) ? $f[1] : null;
  };
  $d = $get('draskykliu-filtras');
  $s = $get('sampunu-filtras');
  $diff = array();
  if(is_array($d)&&is_array($s)){
    $keys = array_unique(array_merge(array_keys($d),array_keys($s)));
    foreach($keys as $k){
      $dv = $d[$k] ?? '(nil)'; $sv = $s[$k] ?? '(nil)';
      if(is_array($dv)) $dv='[array '.count($dv).']'; if(is_array($sv)) $sv='[array '.count($sv).']';
      if($dv !== $sv) $diff[$k]=array('drask'=>$dv,'samp'=>$sv);
    }
  }
  echo wp_json_encode(array('drask_f1'=>$d,'samp_f1'=>$s,'DIFF'=>$diff));
  exit;
}, 99);

add_action('init', function(){
  if ( ! isset($_GET['ps_samp_fix']) ) return;
  if ( ($_GET['k'] ?? '') !== 'ps2026' ) { status_header(403); echo 'no'; exit; }
  header('Content-Type: application/json; charset=utf-8');
  $out = array();

  // 1) PUBLIKUOTI breed draftus (+ readiness)
  $drafts = array(17333,15709,15694,15692,15659,15662,15689);
  $rep = array();
  foreach ($drafts as $id) {
    $st = get_post_status($id);
    $pr = get_post_meta($id,'_price',true);
    $img = (bool) get_post_thumbnail_id($id);
    if ($st && $st !== 'publish') { wp_update_post(array('ID'=>$id,'post_status'=>'publish')); }
    $rep[$id] = array('was'=>$st,'now'=>get_post_status($id),'price'=>($pr!==''?$pr:'NERA'),'img'=>$img?'taip':'NE');
  }
  $out['breeds'] = $rep;

  // 2) YITH preset save (indekso pastatymas kaip per UI)
  $p = get_page_by_path('sampunu-filtras', OBJECT, 'yith_wcan_preset');
  if ($p) {
    $pid = $p->ID;
    $y = array();
    if ( function_exists('yith_wcan_get_preset') ) {
      $obj = yith_wcan_get_preset($pid);
      if ( is_object($obj) ) {
        $y['class'] = get_class($obj);
        if ( method_exists($obj,'save') ) { try { $obj->save(); $y['save']='OK'; } catch(\Throwable $e){ $y['save']=substr($e->getMessage(),0,50); } }
      }
    }
    // fire save_post hooks (UI imitacija)
    wp_update_post(array('ID'=>$pid,'post_status'=>'publish'));
    do_action('save_post', $pid, get_post($pid), true);
    do_action('save_post_yith_wcan_preset', $pid, get_post($pid), true);
    // index/lookup jei yra
    foreach (array('YITH_WCAN_Index','YITH_WCAN_Cache_Helper','YITH_WCAN_Lookup') as $cls) {
      if ( class_exists($cls) ) {
        $y['cls_'.$cls] = array_values(array_filter(get_class_methods($cls), function($m){ return preg_match('/index|lookup|rebuild|cache|flush|regenerate|create/i',$m); }));
        foreach (array('rebuild','rebuild_index','create_lookup_table','regenerate','flush','create_index','index') as $m) {
          if ( method_exists($cls,$m) ) { try { call_user_func(array($cls,$m)); $y['ran_'.$cls.'_'.$m]='OK'; } catch(\Throwable $e){ $y['ran_'.$cls.'_'.$m]=substr($e->getMessage(),0,40); } }
        }
      }
    }
    $out['yith'] = $y;
  }
  // flush
  global $wpdb;
  $wpdb->query("DELETE FROM {$wpdb->options} WHERE option_name LIKE '\_transient\_yith\_wcan%' OR option_name LIKE '\_transient\_timeout\_yith\_wcan%'");
  if ( function_exists('wp_cache_flush') ) wp_cache_flush();

  // 3) veisle terminu count po publish
  $tax='pa_veisle';
  $terms=get_terms(array('taxonomy'=>$tax,'hide_empty'=>false));
  $tc=array();
  if(!is_wp_error($terms)){ foreach($terms as $t){ $tc[$t->name]=$t->count; } }
  $out['veisle_counts']=$tc;

  echo wp_json_encode($out);
  exit;
}, 99);

