    WC()->customer->set_shipping_state('');
    WC()->customer->set_shipping_postcode('01001');
    WC()->customer->set_shipping_city('Vilnius');
    WC()->cart->calculate_shipping();
    $w = WC()->cart->get_cart_contents_weight();
