  $presets = get_posts(array("post_type"=>"yith_wcan_preset","numberposts"=>20,"post_status"=>"any"));
  $r["presets"] = array();
  foreach($presets as $p){
    $filters = get_post_meta($p->ID, "filters", true);
    $fsum = array();
    if(is_array($filters)){
      foreach($filters as $f){
        $fsum[] = array(
          "title"=>isset($f["title"])?$f["title"]:"",
          "type"=>isset($f["filter_type"])?$f["filter_type"]:"",
          "taxonomy"=>isset($f["taxonomy"])?$f["taxonomy"]:"",
          "terms_mode"=>isset($f["show_terms"])?$f["show_terms"]:(isset($f["terms_logic"])?$f["terms_logic"]:""),
          "terms_count"=>isset($f["terms"])&&is_array($f["terms"])?count($f["terms"]):0
        );
      }
    }
    $r["presets"][] = array("id"=>$p->ID,"title"=>$p->post_title,"slug"=>$p->post_name,"filters"=>$fsum);
  }
  // 2. lookup lentele
  $lookup = $wpdb->prefix . "wc_product_attributes_lookup";
  $exists = $wpdb->get_var("SHOW TABLES LIKE '{$lookup}'");
  $r["lookup_exists"] = $exists ? true : false;
  if($exists){
    $r["lookup_rows"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$lookup}");
