  }
  // 3. terminu skaiciai realus (term_taxonomy)
  $r["term_counts"] = array();
  foreach(array("pa_be_grudu","pa_speciali_mityba","pa_monoprotein") as $tax){
    $terms = get_terms(array("taxonomy"=>$tax,"hide_empty"=>false));
