add_action("wp_loaded", function(){
  if (!isset($_GET["waxfix"]) || $_GET["waxfix"] !== "ps2026") return;
  global $wpdb;
  $log = array();
  // 1. IsTrinam WC atributu taksonomiju cache (kelios versijos)
  delete_transient("wc_attribute_taxonomies");
  $log["transient_deleted"] = "wc_attribute_taxonomies";
  // ir option cache
  wp_cache_delete("wc_attribute_taxonomies", "options");
  wp_cache_delete("attribute_taxonomies", "woocommerce-attributes");
  // 2. force re-fetch is DB
  if(function_exists("wc_get_attribute_taxonomies")){
    // istrinam saugoma cache'a
    $wpdb->query("DELETE FROM {$wpdb->options} WHERE option_name = '_transient_wc_attribute_taxonomies' OR option_name = '_transient_timeout_wc_attribute_taxonomies'");
    // ka DB'e turim?
    $taxes = $wpdb->get_results("SELECT attribute_id, attribute_name, attribute_label, attribute_public FROM {$wpdb->prefix}woocommerce_attribute_taxonomies ORDER BY attribute_id");
    $tsum = array();
    foreach($taxes as $t){ $tsum[]="id{$t->attribute_id}:pa_{$t->attribute_name}(pub={$t->attribute_public})"; }
    $log["db_attrs"] = $tsum;
  }
  // 3. globali WC atributu masyvo isvalymas (jei plugin cache'ina globalinj var)
  global $wc_product_attributes;
  $wc_product_attributes = null;
  // 4. force init taksonomiju - per WC funkcija
  if(function_exists("wc_get_attribute_taxonomy_names")){
    $names = wc_get_attribute_taxonomy_names();
    $log["wc_names_after_flush"] = $names;
  }
  // 5. rankiniu budu registruojam pa_be_grudu ir pa_speciali_mityba jei is DB yra bet neregistr
  foreach(array("pa_be_grudu","pa_speciali_mityba") as $tax){
    if(!taxonomy_exists($tax)){
      // istraukiam is DB
      $slug = str_replace("pa_","",$tax);
      $row = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$wpdb->prefix}woocommerce_attribute_taxonomies WHERE attribute_name = %s", $slug));
      if($row){
        $args = array(
          "labels"=>array("name"=>$row->attribute_label),
          "hierarchical"=>false,
          "show_ui"=>false,
          "query_var"=>true,
          "rewrite"=>false,
          "public"=>true,
          "show_in_nav_menus"=>false,
          "show_in_rest"=>true,
        );
        register_taxonomy($tax, array("product"), $args);
        $log["manual_reg_".$tax] = taxonomy_exists($tax) ? "OK" : "FAIL";
      } else {
        $log["manual_reg_".$tax] = "no_db_row";
      }
    } else {
      $log["already_reg_".$tax] = "yes";
    }
  }
  // 6. hard flush
  flush_rewrite_rules(true);
  $log["flushed"] = true;
  $up = wp_upload_dir();
  file_put_contents($up["basedir"]."/waxfix_result.json", wp_json_encode($log));
  wp_die("WAXFIX_DONE");
});

