  $log["distinct_taxonomies"] = $wpdb->get_col("SELECT DISTINCT taxonomy FROM {$wpdb->prefix}wc_product_attributes_lookup");
  $log["count_be-grudu"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_be-grudu\"");
  $log["count_be_grudu"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_be_grudu\"");
  $log["count_speciali-mityba"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_speciali-mityba\"");
  $log["count_speciali_mityba"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_speciali_mityba\"");
  // 2. Kiek terminu su naujais slug'ais
  foreach(array("pa_be_grudu","pa_speciali_mityba") as $tax){
    if(taxonomy_exists($tax)){
      $terms = get_terms(array("taxonomy"=>$tax,"hide_empty"=>false));
      $log["terms_".$tax] = is_wp_error($terms) ? $terms->get_error_message() : array_map(function($t){return $t->name."(".$t->count.")";}, $terms);
    } else {
      $log["terms_".$tax] = "TAXONOMY NOT REGISTERED";
    }
  }
  $up = wp_upload_dir();
  file_put_contents($up["basedir"]."/lookupdiag.json", wp_json_encode($log));
  wp_die("LOOKUPDIAG_DONE");
});

add_action("wp_loaded", function(){
  if (!isset($_GET["lookupfix2"]) || $_GET["lookupfix2"] !== "ps2026") return;
  global $wpdb;
  $log = array();
  // 1. Update wc_product_attributes_lookup: pa_be-grudu -> pa_be_grudu
  $r1 = $wpdb->update($wpdb->prefix."wc_product_attributes_lookup", array("taxonomy"=>"pa_be_grudu"), array("taxonomy"=>"pa_be-grudu"));
  $log["updated_bg"] = $r1;
  $r2 = $wpdb->update($wpdb->prefix."wc_product_attributes_lookup", array("taxonomy"=>"pa_speciali_mityba"), array("taxonomy"=>"pa_speciali-mityba"));
  $log["updated_sm"] = $r2;
  // 2. clear cache
  wp_cache_flush();
  if(function_exists("wc_delete_product_transients")) wc_delete_product_transients();
  delete_transient("wc_attribute_taxonomies");
  flush_rewrite_rules(true);
  $log["done"] = true;
  // 3. patvirtinimas
  $log["lookup_bg_after"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_be_grudu\"");
  $log["lookup_sm_after"] = (int)$wpdb->get_var("SELECT COUNT(*) FROM {$wpdb->prefix}wc_product_attributes_lookup WHERE taxonomy = \"pa_speciali_mityba\"");
  $up = wp_upload_dir();
  file_put_contents($up["basedir"]."/lookupfix2_result.json", wp_json_encode($log));
  wp_die("LOOKUPFIX2_DONE");
});

/**
 * Petshop Frontpage Setter v1 (TEMP)
 *
 * Vienkartinis snippet'as: pakeicia WP option 'page_on_front' i nurodyta ID.
 * Trigeris: ?fp_update=NNN URL parametras (tik admin userams).
 * Naudojimas: uzeit i https://dev.avesa.lt/?fp_update=34543
 * Rezultatas: page_on_front pakeista, echo confirmation, exit.
 * Po naudojimo snippet'a DEAKTYVUOTI - jis nebereikalingas.
 */
add_action('init', function() {
    if (empty($_GET['fp_update'])) return;
    if (!current_user_can('manage_options')) {
        wp_die('Neuztenka teisiu', 'FP setter', ['response' => 403]);
    }
    $val = intval($_GET['fp_update']);
    if ($val <= 0) {
        wp_die('Netinkamas ID', 'FP setter', ['response' => 400]);
    }
    $page = get_post($val);
    if (!$page || $page->post_status !== 'publish' || $page->post_type !== 'page') {
        wp_die('Puslapis '.$val.' neegzistuoja arba ne publish page', 'FP setter', ['response' => 400]);
    }
    $before = get_option('page_on_front');
    update_option('show_on_front', 'page');
    update_option('page_on_front', $val);
    $after = get_option('page_on_front');
    header('Content-Type: text/plain; charset=utf-8');
    echo "OK\n";
    echo "before page_on_front: $before\n";
    echo "after  page_on_front: $after\n";
    echo "show_on_front: ".get_option('show_on_front')."\n";
    echo "\nPO PATIKROS - snippet'a deaktyvuot.";
    exit;
}, 5);
